import{_ as t,o as r,c as o,a2 as l}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F17: 籌碼分佈與法人動態分析 - 財務審計專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/2492_華新科/20260512/F17_籌碼分佈與法人動態分析.md","filePath":"審計報告庫/財務審計/2492_華新科/20260512/F17_籌碼分佈與法人動態分析.md"}'),i={name:"審計報告庫/財務審計/2492_華新科/20260512/F17_籌碼分佈與法人動態分析.md"};function n(e,a,s,h,d,g){return r(),o("div",null,[...a[0]||(a[0]=[l('<h1 id="f17-籌碼分佈與法人動態分析-財務審計專家-審計報告" tabindex="-1">F17: 籌碼分佈與法人動態分析 - 財務審計專家 審計報告 <a class="header-anchor" href="#f17-籌碼分佈與法人動態分析-財務審計專家-審計報告" aria-label="Permalink to &quot;F17: 籌碼分佈與法人動態分析 - 財務審計專家 審計報告&quot;">​</a></h1><blockquote><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p></blockquote><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>外資、投信與自營商的近期買賣超動向為何？千張大戶持股比例是否發生結構性變化？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：外資一月內持股11.9%→18.8%(+6.84pp)，日均買超千萬股。投信缺席，大戶穩定。外資鎖碼格局。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：截至2026年5月</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>外資買賣超(5月)</strong>：5/5買超+1,225萬、5/6買超+888萬、5/7買超+1,203萬、5/8買超+1,351萬、5/11買超+1,287萬。連續5個交易日大買，合計約5,953萬股。</li><li><strong>外資持股變化</strong>：11.93%(3/31)→14.34%(4/28)→17.44%(5/7)→18.77%(5/11)。升勢陡峭。</li><li><strong>投信/自營商</strong>：投信近乎零參與(每日0-7千股)；自營商小幅買超(每日5-60萬股)。主要動能全來自外資。</li><li><strong>診斷見解</strong>：外資買盤集中且強勁，籌碼從散戶快速流向外資，方向性明確。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="_1-外資買賣超深度分析" tabindex="-1">1. 外資買賣超深度分析 <a class="header-anchor" href="#_1-外資買賣超深度分析" aria-label="Permalink to &quot;1. 外資買賣超深度分析&quot;">​</a></h3><ul><li><strong>買超強度</strong>：4-5月日均買超約800-1,350萬股，以均價170元估算，每日投入資金約13-23億。此種買超力度在台灣中型股中極為罕見。</li><li><strong>買超驅動力</strong>：推測為外資券商對華新科2026年展望轉正向——AI需求(佔營收10%倍增至20%)+漲價效應+Q1 EPS 1.69元優於預期。日系/美系外資為主買盤。</li><li><strong>對比2024年</strong>：2024年外資持股從低點約8-9%緩步上升至12%，整年增幅約3-4pp。2026年一個半月即增6.84pp，速度為2024全年的2倍。</li></ul><h3 id="_2-投信與自營商" tabindex="-1">2. 投信與自營商 <a class="header-anchor" href="#_2-投信與自營商" aria-label="Permalink to &quot;2. 投信與自營商&quot;">​</a></h3><ul><li><strong>投信缺席</strong>：僅零星參與(每日0-5,000股)，一方面反映華新科非投信主流持股(規模偏大、無投信鎖碼行情)，另一方面為正面訊號(無季底結帳壓力)。</li><li><strong>自營商跟單</strong>：每日小幅買超(5-60萬股)，屬避險操作和跟單性質，非主導力量。</li></ul><h3 id="_3-千張大戶與散戶變化" tabindex="-1">3. 千張大戶與散戶變化 <a class="header-anchor" href="#_3-千張大戶與散戶變化" aria-label="Permalink to &quot;3. 千張大戶與散戶變化&quot;">​</a></h3><ul><li><strong>大戶穩定</strong>：千張以上大戶37人(59.32%)。華新麗華集團、國泰人壽等機構法人為主要持有人，持股穩定。</li><li><strong>散戶動向</strong>：總股東數約7.3萬人(5/8)，較年初變化不大。散戶未因股價上漲而大量湧入，籌碼結構維持健康。</li><li><strong>籌碼集中趨勢</strong>：外資加碼→流通在外籌碼減少→有助股價支撐。</li></ul><h2 id="💡-專家評析-多空雙向分析" tabindex="-1">💡 專家評析（多空雙向分析） <a class="header-anchor" href="#💡-專家評析-多空雙向分析" aria-label="Permalink to &quot;💡 專家評析（多空雙向分析）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>外資買超過度集中的後繼無力風險</strong>：外資5日合計買超5,953萬股(約3,327萬股增量)。若基本面利多兌現不如預期，外資可能反手賣出，18.8%的持股一旦轉賣將造成巨大賣壓。</li><li><strong>投信缺席反映法人認同度分歧</strong>：外資獨買而投信零參與，缺乏內外資合力上攻的動力。一旦外資買盤消退，股價動能可能驟降。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>外資連續每日千萬級買超為極罕見訊號</strong>：連續5個交易日每日買超&gt;1,000萬股(中位數約1,200萬)，在台灣股市中僅出現在深度基本面轉折的標的(如2023年的AI供應鏈股)。此為最強的多頭訊號之一。</li><li><strong>大戶與外資雙引擎鎖碼</strong>：大戶持63%+外資持18.8%→約82%籌碼由內部人與外資鎖定。市場流通量僅約18%(約8,700萬股)，以月成交量約20-40萬張看，籌碼結構極度緊縮。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>華新科正處於罕見的外資強力收集期。籌碼從散戶流向法人、大戶穩定不動，為典型的「拉股價先收籌碼」格局。當外資買超趨緩時可能出現短線整理，但中長期籌碼結構已優化。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>原始數據</strong>：FinMind TaiwanStockInstitutionalHolding + TaiwanStockShareholdingSpread</li><li><strong>查詢參數</strong>：stock_id=2492, institutional range=2026-04-01~2026-05-11, spread=2026-05-08</li><li><strong>關鍵核對碼</strong>：外資5/11持有91,216,123股(18.77%) vs 3/31持有57,971,099股(11.93%)</li><li><strong>數據查詢日期</strong>：2026-05-12</li></ul>',24)])])}const c=t(i,[["render",n]]);export{u as __pageData,c as default};
